require "hall.ui.window.GUIChatRecordItem"

local UIChatInput = class("UIChatInput", IGUILayout)

function UIChatInput:onLoad()
    self.etInput = self:getChildWindow("BedWarChatInput-input", GUIType.Edit)
    self.btnClose = self:getChildWindow("BedWarChatInput-close", GUIType.Button)
    self.btnSend = self:getChildWindow("BedWarChatInput-send", GUIType.Button)
    self.llChatRecord = self:getChildWindow("BedWarChatInput-record", GUIType.Layout)
    self:initRegister()
    self.etInput:SetMaxLength(40)
    self.btnSend:SetText(Lang:getString("gui_bedwar_send"))
    self:initChatList()
end

function UIChatInput:isShowAnim()
    return false
end

function UIChatInput:initRegister()
    self.btnClose:registerEvent(GUIEvent.ButtonClick, function()
        GUIBedWarToolBar.cbChat:SetChecked(false)
    end)

    self.btnSend:registerEvent(GUIEvent.ButtonClick, function()
        self:send()
    end)

    self:registerDataCallBack("Chat", function(data)
        self:onGetChat(data)
    end, DataBuilderProcessor)
end

function UIChatInput:send()
    local string = self.etInput:GetText()
    if string == nil or string == "" then
        GUIBedWarToolBar.cbChat:SetChecked(false)
        return
    end
    string = FilterWord.getReplaceContent(string)
    SoundUtil.playSound(SoundConfig.sendMessage)
    GamePacketSender:sendChatMessage(string)
    self.etInput:SetText("")
    GUIBedWarToolBar.cbChat:SetChecked(false)
end

function UIChatInput:initChatList()
    if self.gvChatItems ~= nil then
        self.gvChatItems:destroy()
    end
    self.gvChatItems = IGUIGridView.new("BedWarChatRecordList", self.llChatRecord)
    self.gvChatItems:setArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 1, 0 })
    self.gvChatItems:setConfig(0, 0, 1)
    self.ContentSize = self.llChatRecord:GetPixelSize().x
    self.ScrollOffset = self.llChatRecord:GetPixelSize().y
end

function UIChatInput:onGetChat(data)
    local sendId = data:getNumberParam("userId")
    local text = data:getParam("text")
    self:addChatItem(sendId, text)
end

function UIChatInput:addChatItem(sendId, text)
    local chatItem = GUIChatRecordItem.new("BedWarChatRecordItem.json")
    chatItem:setWidth({ 0, self.ContentSize })
    local name
    local height
    if sendId == 0 then
        height = chatItem:onGetSystemTip(text)
    else
        local user = UserManager.Instance():findUser(sendId)
        if user then
            name = user.userName
            height = chatItem:onGetChat(name, text)
        end
    end
    self.ScrollOffset = self.ScrollOffset - height
    if self.ScrollOffset < 0 then
        LuaTimer:schedule(function()
            self.gvChatItems.root:SetScrollOffset(self.ScrollOffset)
        end, 1)
    end
    chatItem:setHeight({ 0, height })
    self.gvChatItems:addItem(chatItem)
end

return UIChatInput